$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Lülitab puhastaja sisse või välja. Kui see on välja lülitatud, ei kustuta cron URL ega käsitsi käivitamise nupp vanu statistikaid. Kasutage seda lülitit, kui soovite mooduli alles jätta, kuid ajutiselt peatada kogu puhastustegevuse.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Ühenduste statistika säilitamise päevad';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Sellest vanemad read eemaldatakse tabelitest connections, connections_source ja connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Sisestage päevade arv, mille jooksul PrestaShop töötlemata külastajastatistikat säilitatakse. Näide: 60 tähendab, et moodul hoiab viimased 60 päeva ja kustutab vanemad kirjed tabelitest ps_connections, ps_connections_source ja ps_connections_page. Ärge seadke väärtuseks 1, kui te pole kindel, et värsket külastajastatistikat pole vaja.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Paki suurus';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Ühes pakis töödeldavate ühenduste maksimaalne arv.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Sisestage, mitu peamist ühenduse kirjet võib ühes sisemises pakis töödelda. Väiksemad väärtused on nõrgas hostingus turvalisemad, kuid vajavad rohkem cron käivitusi. Suuremad väärtused puhastavad kiiremini, kuid võivad hoida andmebaasilukke kauem. Soovitatav algväärtus: 1000 kuni 5000; suurendage alles pärast käitusaja testimist.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maksimaalne pakkide arv käivituse kohta';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Piirab, kui palju tööd üks cron käivitus teha saab.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Sisestage, mitu pakki võib ühe cron käivituse ajal joosta. Võimalik kustutatud peamiste ühenduse kirjete koguarv käivituse kohta on ligikaudu Paki suurus korda Maksimaalne pakkide arv käivituse kohta. Näide: 5000 ja 10 tähendab kuni umbes 50000 peamist kirjet ühes cron käivituses. Vähendage, kui pood puhastuse ajal aeglustub.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Tühjenda ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Tühjendab faceted/layered otsinguploki vahemälu käsuga TRUNCATE TABLE. MySQL/MariaDB loob tabeli uuesti tühjana.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Lubage see ainult siis, kui ps_layered_filter_block kasvab liiga suureks või sisaldab aegunud faceted otsingu vahemälu. See ei kustuta tooteid, kategooriaid ega layered hinnaindeksit. Pärast puhastust saab PrestaShop või faceted otsingu moodul vahemälu vajadusel uuesti luua.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Koonda liiklusallikate statistika enne kustutamist';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Salvestab igapäevase koondatud liiklusallikate statistika enne töötlemata ridade kustutamist.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Kui see on lubatud, salvestab moodul väikese päevakokkuvõtte enne PrestaShop töötlemata statistika eemaldamist. See hoiab arve nagu külastused, lehevaatamised, allikadomeen ja UTM väärtused. See ei salvesta IP-aadresse, täielikke referrer URL-e ega user-agent stringe. Keelake, kui soovite ainult kustutamist ega vaja ajaloolisi allikakokkuvõtteid.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Koondstatistika säilitamise päevad';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Kui kaua väikest päevakokkuvõtte tabelit säilitada.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Sisestage, mitu päeva koondatud liikluskokkuvõtted peaksid mooduli tabelis püsima. Näide: 730 hoiab umbes kaks aastat igapäevaseid allikakokkuvõtteid. See seade mõjutab ainult tabelit ps_jooim_dbcleaner_traffic_daily, mitte algseid PrestaShop statistikataabeleid.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Aegunud luku ajalimiit sekundites';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Kaitse kahe puhastusprotsessi samaaegse töötamise vastu.';
