$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_924684322fe68e56ef9205e7f480f598'] = 'Tühjendab faceted/layered otsinguploki vahemälu käsuga TRUNCATE TABLE. MySQL/MariaDB loob tabeli uuesti tühjana.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Lubage see ainult siis, kui ps_layered_filter_block kasvab liiga suureks või sisaldab aegunud faceted otsingu vahemälu. See ei kustuta tooteid, kategooriaid ega layered hinnaindeksit. Pärast puhastust saab PrestaShop või faceted otsingu moodul vahemälu vajadusel uuesti luua.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Koonda liiklusallikate statistika enne kustutamist';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Salvestab igapäevase koondatud liiklusallikate statistika enne töötlemata ridade kustutamist.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Kui see on lubatud, salvestab moodul väikese päevakokkuvõtte enne PrestaShop töötlemata statistika eemaldamist. See hoiab arve nagu külastused, lehevaatamised, allikadomeen ja UTM väärtused. See ei salvesta IP-aadresse, täielikke referrer URL-e ega user-agent stringe. Keelake, kui soovite ainult kustutamist ega vaja ajaloolisi allikakokkuvõtteid.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Koondstatistika säilitamise päevad';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Kui kaua väikest päevakokkuvõtte tabelit säilitada.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Sisestage, mitu päeva koondatud liikluskokkuvõtted peaksid mooduli tabelis püsima. Näide: 730 hoiab umbes kaks aastat igapäevaseid allikakokkuvõtteid. See seade mõjutab ainult tabelit ps_jooim_dbcleaner_traffic_daily, mitte algseid PrestaShop statistikataabeleid.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Aegunud luku ajalimiit sekundites';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Kaitse kahe puhastusprotsessi samaaegse töötamise vastu.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Sisestage sekundite arv, mille järel lõpetamata puhastuslukk loetakse hüljatuks. See kaitseb andmebaasi kahe samaaegse cron käivituse eest. Soovitatav väärtus: 7200. Vähendage ainult siis, kui cron lõpetab kindlasti kiiresti.';
